B.a0g=new A.aL("T\xe4gliche Belohnung bereits abgeholt",null,null,null,null,null,null,null,null,null)
B.a0h=new A.aL("Vielen Dank f\xfcr Ihr Interesse an unserer Studie. Leider d\xfcrfen aus rechtlichen Gr\xfcnden nur Personen mit einem Mindestalter von 18 Jahren an unsere Studie teilnehmen.",null,null,null,null,null,null,null,null,null)
B.a0i=new A.aL("Dr\xfccken Sie auf den \u201eTeilen\u201c-Button (kleine Viereck mit dem Pfeil nach oben) -> Option -> zum Home-Bildschirm",null,B.dm,B.L,null,null,null,null,null,null)
B.a0j=new A.aL("Viel Spa\xdf beim Spielen!\n          ",null,B.bp,null,null,null,null,null,null,null)
B.C5=new A.aL("Keine Z\xfcge mehr m\xf6glich",null,null,null,null,null,null,null,null,null)
