B.a0l=new A.aL("5.\tBewegungsbegrenzung und Zeitlimit: ",null,B.bp,null,null,null,null,null,null,null)
B.a0m=new A.aL("Jedes Level hat spezifische Ziele, wie das Erreichen einer bestimmten Punktzahl, das Sammeln einer Anzahl von bestimmten Jellies oder das Entfernen von Hindernissen. Das jeweilige Ziel wird in dem Kasten rechts oben auf dem Bildschirm angezeigt\n              ",null,null,null,null,null,null,null,null,null)
B.a0n=new A.aL("Du hast nicht genug M\xfcnzen um dieses Level freizuschalten",null,null,null,null,null,null,null,null,null)
B.a0q=new A.aL("Einige Level haben eine begrenzte Anzahl von Z\xfcgen oder ein Zeitlimit, um die Ziele zu erreichen. Dies wird in dem Kasten links oben auf dem Bildschirm angezeigt.\n          ",null,null,null,null,null,null,null,null,null)
